// the raw inner SVG content for a family — for SVG contexts (e.g. the 2D board) where ShapeGlyph's <svg> can't nest
// in <text>. The CONSUMER must wrap it in `<svg fill="currentColor" style={{ color }}>` (mirroring ShapeGlyph)
// for tint to work; without that, currentColor falls back to the inherited text colour.
export const shapeGlyphInner = (family: string): ReactNode | null => CHIBI[family] ?? null

export function ShapeGlyph({ family, size = '1em', color, label }: { family: string; size?: number | string; color?: string; label?: string }) {
  // Decorative by default (aria-hidden) since the glyph usually sits beside a nickname. Pass `label` where the
  // glyph is the ONLY identifier (loadout/party rows) to expose it to assistive tech as role=img with the name.
  const aria = label ? { role: 'img' as const, 'aria-label': label } : { 'aria-hidden': true }
  const chibi = CHIBI[family]
  if (chibi) {
    return (
      <svg {...aria} width={size} height={size} viewBox="0 0 24 24" fill="currentColor" style={{ display: 'inline-block', verticalAlign: 'middle', flexShrink: 0, overflow: 'visible', color }}>
        {chibi}
      </svg>
    )
  }
  // not drawn yet → the existing emoji. Match the SVG branch: same alignment/shrink, color pass-through (harmless
  // for emoji, but tints the textual '✦' fallback), and the same aria treatment.
  return <span {...aria} style={{ fontSize: size, lineHeight: 1, display: 'inline-block', verticalAlign: 'middle', flexShrink: 0, color }}>{glyphOf(family)}</span>
}
